import React, { useEffect, useState } from "react";
import axios from "axios";
import { motion } from "framer-motion";

const NotesCards = () => {

    const userId = "user123";

    const [todos, setTodos] = useState([]);
    const [categories, setCategories] = useState([]);

    const [search, setSearch] = useState("");
    const [selectedCategory, setSelectedCategory] = useState("");

    const [selectedTodo, setSelectedTodo] = useState(null); // ✅ NEW

    // FETCH TODOS
    const fetchTodos = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/todos?userId=${userId}`
            );
            setTodos(res.data);
        } catch (err) {
            console.error("TODO ERROR 👉", err);
        }
    };

    // FETCH CATEGORIES
    const fetchCategories = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/categories?userId=${userId}`
            );
            setCategories(res.data);
        } catch (err) {
            console.error("CATEGORY ERROR 👉", err);
        }
    };

    const getCategoryColor = (categoryName) => {
        const found = categories.find(
            (cat) => cat.name === categoryName
        );
        return found ? found.color : "#6b7280";
    };

    useEffect(() => {
        fetchTodos();
        fetchCategories();
    }, []);

    // TOGGLE
    const handleToggle = async (id) => {
        try {
            await axios.put(
                `http://localhost:5001/api/todos/toggle/${id}`
            );
            fetchTodos();
        } catch (err) {
            console.error(err);
        }
    };

    // FILTER
    const filteredTodos = todos.filter((todo) => {

        const matchesSearch =
            todo.title.toLowerCase().includes(search.toLowerCase()) ||
            (todo.description || "")
                .toLowerCase()
                .includes(search.toLowerCase());

        const matchesCategory =
            selectedCategory === "" ||
            todo.category === selectedCategory;

        return matchesSearch && matchesCategory;
    });

    return (
        <div className="p-6">

            {/* SEARCH + CATEGORY */}
            <div className="flex flex-col md:flex-row gap-4 mb-8 max-w-5xl mx-auto">

                <input
                    type="text"
                    placeholder="Search tasks..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="flex-1 px-5 py-3 rounded-2xl bg-white/10 backdrop-blur-lg border border-white/20 text-white"
                />

                <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="px-5 py-3 rounded-2xl bg-white/10 backdrop-blur-lg border border-white/20 text-white"
                >
                    <option value="" className="text-black">
                        All Categories
                    </option>

                    {categories.map((cat) => (
                        <option key={cat._id} value={cat.name} className="text-black">
                            {cat.name}
                        </option>
                    ))}
                </select>

            </div>

            {/* CARDS */}
            <motion.div layout className="grid  sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">

                {filteredTodos.length === 0 ? (
                    <p className="text-white text-center col-span-full text-lg">
                        No Tasks Found
                    </p>
                ) : (
                    filteredTodos.map((todo) => (

                        <motion.div
                            key={todo._id}
                            onClick={() => setSelectedTodo(todo)} // ✅ CLICK OPEN
                            initial={{ opacity: 0, y: 40 }}
                            animate={{ opacity: 1, y: 0 }}
                            whileHover={{ scale: 1.05 }}
                            transition={{ duration: 0.3 }}
                            className="cursor-pointer overflow-auto relative bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl p-5 text-white shadow-xl flex flex-col justify-between h-[240px]"
                        >

                            <span
                                className="text-xs w-fit px-3 py-1 rounded-full font-medium"
                                style={{
                                    backgroundColor: getCategoryColor(todo.category),
                                }}
                            >
                                {todo.category}
                            </span>

                            <div>
                                <h3 className="text-lg font-semibold mt-2 truncate">
                                    {todo.title}
                                </h3>

                                <p className="text-sm text-white/70 mt-2 line-clamp-3">
                                    {todo.description}
                                </p>
                            </div>

                            <div className="mt-4">
                                {todo.completed ? (
                                    <button className="w-full py-2 rounded-xl bg-green-500">
                                        ✅ Completed
                                    </button>
                                ) : (
                                    <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            handleToggle(todo._id);
                                        }}
                                        className="w-full py-2 rounded-xl bg-white text-black"
                                    >
                                        Mark as Completed
                                    </button>
                                )}
                            </div>

                            <div
                                className="absolute left-0 top-0 h-full w-1 rounded-l-2xl"
                                style={{
                                    backgroundColor: getCategoryColor(todo.category),
                                }}
                            />

                        </motion.div>
                    ))
                )}

            </motion.div>

            {/* 🔥 MODAL */}
            {selectedTodo && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center z-50">

                    <div className="relative bg-[#1f274a] w-[90%] max-w-md p-6 rounded-2xl text-white shadow-2xl">

                        {/* CLOSE */}
                        <button
                            onClick={() => setSelectedTodo(null)}
                            className="absolute top-4 right-4 text-xl"
                        >
                            ✖
                        </button>

                        {/* CATEGORY */}
                        <span
                            className="px-3 py-1 rounded-full text-xs"
                            style={{
                                backgroundColor: getCategoryColor(selectedTodo.category),
                            }}
                        >
                            {selectedTodo.category}
                        </span>

                        {/* TITLE */}
                        <h2 className="text-2xl font-bold mt-4">
                            {selectedTodo.title}
                        </h2>

                        {/* DESC */}
                        <p className="mt-3 text-white/80">
                            {selectedTodo.description || "No description"}
                        </p>

                        {/* STATUS */}
                        <div className="mt-4">
                            {selectedTodo.completed ? (
                                <span className="bg-green-500 px-3 py-1 rounded-lg">
                                    Completed
                                </span>
                            ) : (
                                <span className="bg-yellow-400 text-black px-3 py-1 rounded-lg">
                                    Pending
                                </span>
                            )}
                        </div>

                    </div>

                </div>
            )}

        </div>
    );
};

export default NotesCards;
